input.new_string:
const PROCESSING_FEE = 5;
const BASE_PREMIUM_SWORD = 100;
const FIRST_INSURANCE_RATE = 0.1;

export function processScenario(scenario: any): unknown {
  const step = scenario.steps[0];
  const items = step.items;

  let base = 0;
  for (const item of items) {
    if (item.type === "sword") {
      base += BASE_PREMIUM_SWORD;
    }
  }

  const firstInsurance = base * FIRST_INSURANCE_RATE;
  const premium = base + firstInsurance + PROCESSING_FEE;

  return { results: [{ premium }] };
}

